TriggerOraclev10g.body:
DECLARE
    vblob                BLOB;
BEGIN
    IF :new.contenido_blob IS NOT NULL
    THEN
        IF :new.nombre_archivo IS NOT NULL
        THEN
            vblob := :new.contenido_blob;
            uti_ge_archivos_pkg.p_grabar_blob_archivo (
                vblob,
                :new.nombre_archivo_almacenado);
        END IF;
    END IF;
END;
